// Prepare Params
const interval = $json.interval || "1d";
const period = $json.period || "1y";

return [{
  json: {
    interval,
    period,
  }
}];

const symbols = ["^FCHI","BNP.PA","AIR.PA","MC.PA","OR.PA","ORA.PA"];

return symbols.map(symbol => ({
  json: {
    symbol,
    interval: $json.interval,
    period: $json.period,
  }
}));

function clamp(x, a, b) { return Math.max(a, Math.min(b, x)); }

function rsi14(closes) {
  const n = 14;
  if (!Array.isArray(closes) || closes.length < n + 1) return null;

  let gains = 0, losses = 0;
  const start = closes.length - (n + 1);

  for (let i = start + 1; i < start + 1 + n; i++) {
    const diff = closes[i] - closes[i - 1];
    if (diff >= 0) gains += diff;
    else losses += -diff;
  }
  gains /= n; losses /= n;

  for (let i = start + 1 + n; i < closes.length; i++) {
    const diff = closes[i] - closes[i - 1];
    const gain = diff > 0 ? diff : 0;
    const loss = diff < 0 ? -diff : 0;
    gains = (gains * (n - 1) + gain) / n;
    losses = (losses * (n - 1) + loss) / n;
  }

  if (losses === 0) return 100;
  const rs = gains / losses;
  return 100 - (100 / (1 + rs));
}

function annualTrendPct(firstClose, lastClose) {
  if (!Number.isFinite(firstClose) || !Number.isFinite(lastClose) || firstClose === 0) return null;
  return ((lastClose / firstClose) - 1) * 100;
}

function vol20AnnualPct(closes) {
  if (!Array.isArray(closes) || closes.length < 21) return null;

  const tail = closes.slice(-21);
  const rets = [];
  for (let i = 1; i < tail.length; i++) {
    const a = tail[i - 1], b = tail[i];
    if (!Number.isFinite(a) || !Number.isFinite(b) || a <= 0 || b <= 0) continue;
    rets.push(Math.log(b / a));
  }
  if (rets.length < 10) return null;

  const mean = rets.reduce((s, x) => s + x, 0) / rets.length;
  const varr = rets.reduce((s, x) => s + (x - mean) ** 2, 0) / (rets.length - 1);
  const dailyStd = Math.sqrt(varr);
  const annStd = dailyStd * Math.sqrt(252);
  return annStd * 100;
}

function signalFrom(trendPct, rsi) {
  if (!Number.isFinite(trendPct) || !Number.isFinite(rsi)) return "NEUTRE";
  if (trendPct > 2 && rsi < 70) return "ACHAT";
  if (trendPct < -2 && rsi > 30) return "VENTE";
  return "NEUTRE";
}

function scoreFrom(trendPct, rsi, volPct) {
  if (!Number.isFinite(trendPct) || !Number.isFinite(rsi) || !Number.isFinite(volPct)) return 0;
  const t = clamp(trendPct / 10, -3, 3);
  const r = clamp((50 - rsi) / 12.5, -2, 2) * -1;
  const v = clamp((20 - volPct) / 20, -1, 1) * 0.8;
  return clamp(t + r + v, -5, 5);
}

function lectureText(signal, trendPct, volPct) {
  const t =
    !Number.isFinite(trendPct) ? "tendance inconnue"
    : trendPct > 3 ? "tendance haussière"
    : trendPct < -3 ? "tendance baissière"
    : "tendance neutre";

  const v =
    !Number.isFinite(volPct) ? "volatilité inconnue"
    : volPct < 15 ? "volatilité calme"
    : volPct < 25 ? "volatilité normale"
    : "volatilité élevée";

  return `${signal} • ${t} • ${v}`;
}

// ---------------------------------------------

const rows = [];
const assets = [];
let achat = 0, vente = 0, neutre = 0;

for (const it of items) {
  const j = it.json || {};
  const symbol = j.symbol || "UNKNOWN";

  if (j.error) {
    assets.push({
      symbol,
      status: "error",
      warning: j.error,
      nb_candles: j.meta?.nb_candles ?? null,
      source: j.meta?.source ?? null,
      interval: j.meta?.interval ?? null,
      period: j.meta?.period ?? null,
    });
    continue;
  }

  const lastClose = j.last_close;
  const firstClose = j.first_close;
  const closes60 = j.closes_60 || [];

  const rsi = rsi14(closes60);
  const trendPct = annualTrendPct(firstClose, lastClose);
  const volPct = vol20AnnualPct(closes60);

  const signal = signalFrom(trendPct, rsi);
  const score = scoreFrom(trendPct, rsi, volPct);
  const lecture = lectureText(signal, trendPct, volPct);

  if (signal === "ACHAT") achat++;
  else if (signal === "VENTE") vente++;
  else neutre++;

  rows.push({
    symbol,
    prix: Number.isFinite(lastClose) ? +lastClose.toFixed(6) : null,
    signal,
    score: +score.toFixed(6),
    tendance_annuelle_pct: Number.isFinite(trendPct) ? +trendPct.toFixed(6) : null,
    vol20_annuelle_pct: Number.isFinite(volPct) ? +volPct.toFixed(6) : null,
    rsi14: Number.isFinite(rsi) ? +rsi.toFixed(6) : null,
    lecture
  });

  assets.push({
    symbol,
    status: "ok",
    nb_candles: j.meta?.nb_candles ?? null,
    source: j.meta?.source ?? null,
    interval: j.meta?.interval ?? null,
    period: j.meta?.period ?? null,
    warning: null
  });
}

rows.sort((a, b) => (b.score ?? -999) - (a.score ?? -999));

const validTrend = rows.map(r => r.tendance_annuelle_pct).filter(Number.isFinite);
const validVol = rows.map(r => r.vol20_annuelle_pct).filter(Number.isFinite);

const avgTrend = validTrend.length ? validTrend.reduce((s,x)=>s+x,0)/validTrend.length : null;
const avgVol = validVol.length ? validVol.reduce((s,x)=>s+x,0)/validVol.length : null;

const summary = {
  nb_assets: rows.length,
  achat,
  vente,
  neutre,
  tendance_moyenne_pct: Number.isFinite(avgTrend) ? +avgTrend.toFixed(1) : null,
  volatilite_moyenne_pct: Number.isFinite(avgVol) ? +avgVol.toFixed(1) : null,
  text: (() => {
    const t = Number.isFinite(avgTrend) ? `${avgTrend.toFixed(1)} %` : "N/A";
    const v = Number.isFinite(avgVol) ? `${avgVol.toFixed(1)} %` : "N/A";
    return `Le marché apparaît équilibré, avec une tendance moyenne de ${t} par an et une volatilité moyenne autour de ${v}.`;
  })(),
  generated_at: new Date().toISOString()
};

return [{
  json: {
    market_ai_summary: summary,
    market_ai_rows: rows,
    market_radar_assets: assets
  }
}];

// n8n Function node: "Assemble Full Daily" ✅
// Version robuste + FIX TechRadar root + NORMALISATION MLOps

// --- helpers ---
function isObj(v) {
  return v && typeof v === "object" && !Array.isArray(v);
}

function deepMerge(target, src) {
  if (!isObj(src)) return target;

  for (const [k, v] of Object.entries(src)) {
    if (v === undefined || v === null) continue;

    if (Array.isArray(v)) {
      const cur = target[k];
      if (!Array.isArray(cur) || v.length >= cur.length) target[k] = v;
      continue;
    }

    if (isObj(v)) {
      if (!isObj(target[k])) target[k] = {};
      deepMerge(target[k], v);
      continue;
    }

    target[k] = v;
  }
  return target;
}

function pickFirst(obj, keys, fallback = null) {
  for (const k of keys) {
    if (obj && obj[k] !== undefined && obj[k] !== null) return obj[k];
  }
  return fallback;
}

function normalize(out) {
  // --- TECH ---
  out.tech_radar = pickFirst(out, ["tech_radar", "techRadar", "tech"], null);

  // --- MARKET ---
  out.market_ai_summary = pickFirst(out, ["market_ai_summary", "market_summary"], null);
  out.market_ai_rows = pickFirst(out, ["market_ai_rows", "market_rows_table"], []);
  out.market_radar_assets = pickFirst(out, ["market_radar_assets", "market_assets", "assets"], []);

  out.market_rows_md = pickFirst(
    out,
    ["market_rows_md", "marketRowsMd", "market_rows_markdown"],
    out.market_rows_md
  );

  // --- MLOps ---
  out.mlops_summary = pickFirst(out, ["mlops_summary"], null);
  out.mlops_kpis = pickFirst(out, ["mlops_kpis"], null);
  out.mlops_decision = pickFirst(out, ["mlops_decision"], null);
  out.mlops_champions_rows = pickFirst(
    out,
    ["mlops_champions_rows", "champions", "mlops_champions"],
    []
  );

  // --- FIX Tech Radar root ---
  const looksLikeTechRadarRoot =
    out.tech_radar === null &&
    out.type === "tech_radar" &&
    isObj(out.metrics);

  if (looksLikeTechRadarRoot) {
    out.tech_radar = {
      type: out.type,
      status: out.status,
      quality: out.quality,
      headline: out.headline,
      fetched_at: out.fetched_at,
      metrics: out.metrics,
      _raw: out._raw,
    };

    delete out.type;
    delete out.status;
    delete out.quality;
    delete out.headline;
    delete out.fetched_at;
    delete out.metrics;
    delete out._raw;
    delete out.join_key;
  }

  // --- Standard ---
  out.workflow = out.workflow || "StormCopilot Daily Full";
  out.generated_at = out.generated_at || new Date().toISOString();

  // --- Sécu types ---
  if (!Array.isArray(out.market_ai_rows)) out.market_ai_rows = [];
  if (!Array.isArray(out.market_radar_assets)) out.market_radar_assets = [];
  if (!Array.isArray(out.mlops_champions_rows)) out.mlops_champions_rows = [];

  return out;
}

// --- FUSION ---
let merged = {};
for (const it of items) {
  if (it?.json) deepMerge(merged, it.json);
}

const out = normalize(merged);
return [{ json: out }];

// n8n Code node: "Format MLOps Champions" ✅ ultra-robuste + nettoyage

const data = items[0]?.json || {};

// 1) Partir de raw_champions si déjà rempli
let raw = (data.raw_champions && typeof data.raw_champions === "object")
  ? data.raw_champions
  : {};

// 2) Si vide, reconstruire depuis les clés racines (^FCHI, BNP.PA, etc.)
if (Object.keys(raw).length === 0) {
  raw = {};
  for (const [k, v] of Object.entries(data)) {
    if (!v || typeof v !== "object" || Array.isArray(v)) continue;
    if (typeof v.run_id === "string" && v.metrics && typeof v.metrics === "object" && ("score" in v)) {
      raw[k] = v;
    }
  }
}

// 3) Construire la table
const entries = Object.entries(raw);
entries.sort(([, a], [, b]) => (b?.score ?? -999) - (a?.score ?? -999));

const fmt = (x, digits = 3) => {
  const n = Number(x);
  return Number.isFinite(n) ? n.toFixed(digits) : "-";
};

let md = "";
md += `## 🧠 StormCopilot – MLOps Champions\n\n`;
md += `Nombre d’actifs analysés : **${entries.length}**\n\n`;
md += `| Symbole | Score | Silhouette | AE Recons. | run_id |\n`;
md += `|---------|------:|----------:|----------:|--------|\n`;

for (const [symbol, payload] of entries) {
  const m = payload?.metrics || {};
  md += `| ${symbol} | ${fmt(payload?.score)} | ${fmt(m.silhouette)} | ${fmt(m.ae_reconstruction)} | ${payload?.run_id || ""} |\n`;
}

md += `\n> Le score combine la qualité du clustering (silhouette) et l’erreur de reconstruction de l’autoencodeur.\n`;

// 4) Nettoyage: supprimer les champions au niveau racine (pour une réponse plus propre)
const clean = { ...data };
for (const sym of Object.keys(raw)) delete clean[sym];

// 5) Output final
return [{
  json: {
    ...clean,
    raw_champions: raw,
    summary_text: md,
  }
}];

// n8n Function node: "Format Daily Summary" ✅
// Version complète avec section MLOps

const d = items[0]?.json || {};
const generatedAt = d.generated_at || new Date().toISOString();

// ---------------- TECH RADAR ----------------
const tech = d.tech_radar || {};
const techMetrics = tech.metrics || {};
const techQuality = tech.quality || (tech.status === "ok" ? "✅ Complet" : "⚠️ Incomplet");
const techHeadline = tech.headline || "";
const techFetched = tech.fetched_at || "";

const sourcesOk = techMetrics.sources_ok ?? techMetrics.nb_ok ?? 0;
const sourcesTotal = techMetrics.sources_total ?? 0;
const hot = techMetrics.hot ?? 0;
const trending = techMetrics.trending ?? 0;
const fresh = techMetrics.fresh ?? 0;

// ---------------- MARKET ----------------
const msum = d.market_ai_summary || {};
const nbAssets = msum.nb_assets ?? d.market_ai_rows.length;
const achat = msum.achat ?? 0;
const vente = msum.vente ?? 0;
const neutre = msum.neutre ?? 0;
const trend = msum.tendance_moyenne_pct ?? null;
const vol = msum.volatilite_moyenne_pct ?? null;
const synth = msum.text || "";

const interval = d.market_radar_assets?.[0]?.interval || "";
const period = d.market_radar_assets?.[0]?.period || "";

const marketRowsMd = d.market_rows_md || "_Aucune ligne IA._";

// Assets table
let assetsMd = "";
if (d.market_radar_assets?.length) {
  assetsMd += `| Symbole | Nb. bougies | Source | Intervalle | Période |\n`;
  assetsMd += `|---|---:|---|---|---|\n`;
  for (const a of d.market_radar_assets) {
    assetsMd += `| ${a.symbol} | ${a.nb_candles} | ${a.source} | ${a.interval} | ${a.period} |\n`;
  }
} else {
  assetsMd = "_Aucun asset._";
}

// ---------------- MLOps ----------------
const mk = d.mlops_kpis || {};
const mdc = d.mlops_decision || {};
const champs = Array.isArray(d.mlops_champions_rows) ? d.mlops_champions_rows : [];

let mlopsTable = "_Aucun champion MLOps._";
if (champs.length) {
  mlopsTable = `| Symbole | Silhouette | AE recon | Score | run_id |\n`;
  mlopsTable += `|---|---:|---:|---:|---|\n`;
  for (const c of champs) {
    mlopsTable += `| ${c.symbol} | ${c.silhouette?.toFixed(3)} | ${c.ae_reconstruction?.toFixed(3)} | ${c.score?.toFixed(3)} | ${c.run_id} |\n`;
  }
}

// ---------------- MARKDOWN FINAL ----------------
const md =
`# 📊 StormCopilot – Rapport quotidien

Généré automatiquement par **StormCopilot** (n8n + FastAPI).

## 📡 Tech Radar – Veille technologique
${techHeadline ? `> ${techHeadline}\n` : ""}

| Indicateur | Valeur |
|---|---|
| Qualité globale | ${techQuality} |
| Sources actives | ${sourcesOk} / ${sourcesTotal} |
| Hot | ${hot} |
| Trending | ${trending} |
| Fresh | ${fresh} |

${techFetched ? `Dernière collecte : ${techFetched}\n` : ""}

## 📈 Market Radar – Analyse des actifs (IA)

| Indicateur | Valeur |
|---|---|
| Actifs analysés | ${nbAssets} |
| ACHAT | ${achat} |
| VENTE | ${vente} |
| NEUTRE | ${neutre} |
| Tendance moyenne | ${trend !== null ? `${trend}%` : ""} |
| Volatilité moyenne | ${vol !== null ? `${vol}%` : ""} |
| Intervalle | ${interval} |
| Période | ${period} |

${synth ? `> ${synth}\n` : ""}

### Détail IA par symbole
${marketRowsMd}

### Données marché
${assetsMd}

## 🧠 MLOps – Monitoring & décision

| Indicateur | Valeur |
|---|---|
| Pipeline | ${mk.pipeline_status || "—"} |
| Champions | ${mk.nb_champions ?? "—"} |
| Drift moyen | ${mdc.drift_avg?.toFixed(3) ?? "—"} |
| Drift max | ${mdc.drift_max?.toFixed(3) ?? "—"} |
| Retrain recommandé | ${mdc.retrain_recommended ? "OUI" : "NON"} |

### Champions MLOps
${mlopsTable}

---

Dernière exécution : ${generatedAt}
`;

return [{ json: { ...d, summary_text: md } }];

// n8n Function node: "Build Market Rows"

const data = items[0]?.json || {};
const rows = Array.isArray(data.market_ai_rows) ? data.market_ai_rows : [];

function n(x, d = 0) {
  const v = Number(x);
  return Number.isFinite(v) ? v : d;
}
function f(x, digits = 2) {
  return n(x).toFixed(digits);
}

const tableRows = rows.map(r => ({
  symbol: String(r.symbol || ""),
  prix: n(r.prix),
  signal: String(r.signal || ""),
  score: n(r.score),
  tendance_annuelle_pct: n(r.tendance_annuelle_pct),
  vol20_annuelle_pct: n(r.vol20_annuelle_pct),
  rsi14: n(r.rsi14),
  lecture: String(r.lecture || "")
}));

// Markdown table
let md = "";
if (tableRows.length > 0) {
  md += `| Symbole | Prix | Signal | Score | Tendance % | Vol20 % | RSI14 | Lecture |\n`;
  md += `|---|---:|---|---:|---:|---:|---:|---|\n`;
  for (const r of tableRows) {
    md += `| ${r.symbol} | ${f(r.prix, 3)} | ${r.signal} | ${f(r.score, 2)} | ${f(r.tendance_annuelle_pct, 1)} | ${f(r.vol20_annuelle_pct, 1)} | ${f(r.rsi14, 1)} | ${r.lecture} |\n`;
  }
} else {
  md = "_Aucune ligne IA (market_ai_rows vide)._";
}

return [{
  json: {
    ...data,
    market_rows_table: tableRows,
    market_rows_md: md
  }
}];

// n8n Function node: "Build Human Text Daily" ✅ (updated with MLOps)

const d = items[0]?.json || {};

function cleanHumanText(s) {
  if (!s) return s;

  // supprime les lignes PowerShell / curl
  s = s.replace(/^.*\bcurl\.exe\b.*$/gmi, "");
  s = s.replace(/^.*\(\.venv\)\s+PS\s+.*$/gmi, "");

  // compact espaces
  s = s.replace(/\n{3,}/g, "\n\n").trim();
  return s;
}

const gen = d.generated_at || new Date().toISOString();

// ---------------- TECH ----------------
const tech = d.tech_radar || {};
const met = tech.metrics || {};
const quality = tech.quality || (tech.status === "ok" ? "✅ Complet" : "⚠️ Incomplet");
const headline = tech.headline || "";
const srcOk = met.sources_ok ?? met.nb_ok ?? 0;
const srcTotal = met.sources_total ?? 0;
const hot = met.hot ?? 0;
const trending = met.trending ?? 0;
const fresh = met.fresh ?? 0;
const fetched = tech.fetched_at || "";

// ---------------- MARKET ----------------
const m = d.market_ai_summary || {};
const rows = Array.isArray(d.market_ai_rows) ? d.market_ai_rows : [];

const nb = m.nb_assets ?? rows.length ?? 0;
const achat = m.achat ?? 0;
const vente = m.vente ?? 0;
const neutre = m.neutre ?? 0;
const trend = m.tendance_moyenne_pct ?? null;
const vol = m.volatilite_moyenne_pct ?? null;
const synth = m.text || "";

// ---------------- MLOPS ----------------
const mk = d.mlops_kpis || {};
const md = d.mlops_decision || {};
const champs = Array.isArray(d.mlops_champions_rows) ? d.mlops_champions_rows : [];

const pipeline = mk.pipeline_status || "—";
const nbChampions = mk.nb_champions ?? champs.length ?? "—";
const driftAvg = md.drift_avg ?? mk.drift_avg ?? null;
const driftMax = md.drift_max ?? mk.drift_max ?? null;
const retrain = (md.retrain_recommended ?? mk.retrain_recommended) ? "🔴 OUI" : "🟢 NON";
const decisionExplain = md.explanation || md.decision_explanation || "";

// ---------------- TEXT ----------------
let txt = `=== StormCopilot — Daily Full (Résumé lisible) ===
Généré: ${gen}

📡 TECH RADAR
- Qualité: ${quality}
${headline ? `- Headline: ${headline}\n` : ""}- Sources: ${srcOk}/${srcTotal} | Hot: ${hot} | Trending: ${trending} | Fresh: ${fresh}
${fetched ? `- Fetched: ${fetched}\n` : ""}

📈 MARKET (IA)
- Actifs: ${nb}
- Signaux: ACHAT ${achat} | VENTE ${vente} | NEUTRE ${neutre}
- Moyennes: tendance ${trend !== null ? trend + "%" : ""} | volatilité ${vol !== null ? vol + "%" : ""}
${synth ? `- Synthèse: ${synth}\n` : ""}

Détail par symbole:
`;

if (!rows.length) {
  txt += "- (Aucun détail IA)\n";
} else {
  for (const r of rows) {
    txt += `- ${r.symbol}: ${r.signal} | score ${Number(r.score ?? 0).toFixed(2)} | prix ${Number(r.prix ?? 0).toFixed(3)} | RSI ${Number(r.rsi14 ?? 0).toFixed(1)} | trend ${Number(r.tendance_annuelle_pct ?? 0).toFixed(1)}% | vol20 ${Number(r.vol20_annuelle_pct ?? 0).toFixed(1)}% | ${r.lecture || ""}\n`;
  }
}

// ---- MLOps section appended ----
txt += `

🧠 MLOps (Daily)
- Pipeline: ${pipeline}
- Champions: ${nbChampions}
- Drift avg: ${driftAvg !== null ? Number(driftAvg).toFixed(3) : "—"} | Drift max: ${driftMax !== null ? Number(driftMax).toFixed(3) : "—"}
- Retrain: ${retrain}
${decisionExplain ? `- Décision: ${decisionExplain}\n` : ""}

Top champions:
`;

if (!champs.length) {
  txt += "- (Aucun champion)\n";
} else {
  for (const c of champs.slice(0, 6)) {
    txt += `- ${c.symbol}: score ${Number(c.score ?? 0).toFixed(3)} | sil ${Number(c.silhouette ?? 0).toFixed(3)} | ae ${Number(c.ae_reconstruction ?? 0).toFixed(3)} | run_id ${c.run_id || ""}\n`;
  }
}

txt += `\n✅ Fin du résumé.\n`;

txt = cleanHumanText(txt);

return [{ json: { ...d, human_text: txt } }];

// n8n Code node: Compress OHLCV → Features (multi-items safe)
// Input: each item = { symbol, interval, period, bars: [...] } or similar
// Output: 1 item per symbol with minimal closes_60

function pickClose(c) {
  if (!c) return null;
  if (typeof c.close === 'number') return c.close;
  if (typeof c.c === 'number') return c.c;
  if (typeof c.adjClose === 'number') return c.adjClose;
  if (typeof c.adj_close === 'number') return c.adj_close;
  return null;
}

function findBars(j) {
  return (
    j.bars ||
    j.candles ||
    j.data ||
    j.ohlcv ||
    j.prices ||
    []
  );
}

return items.map((it) => {
  const j = it.json || {};
  const symbol = j.symbol || j.ticker || j.sym || j.asset || 'UNKNOWN';

  const bars = findBars(j);
  const nbBars = Array.isArray(bars) ? bars.length : (j.nb_candles ?? null);

  if (!Array.isArray(bars) || bars.length < 20) {
    return {
      json: {
        symbol,
        error: `Not enough bars (got ${Array.isArray(bars) ? bars.length : 'N/A'})`,
        meta: {
          nb_candles: nbBars,
          interval: j.interval ?? null,
          period: j.period ?? null,
          source: j.source ?? null,
        }
      }
    };
  }

  const closesAll = bars
    .map(pickClose)
    .filter(v => typeof v === 'number' && Number.isFinite(v));

  if (closesAll.length < 20) {
    return {
      json: {
        symbol,
        error: `Not enough valid closes (got ${closesAll.length})`,
        meta: {
          nb_candles: nbBars,
          interval: j.interval ?? null,
          period: j.period ?? null,
          source: j.source ?? null,
        }
      }
    };
  }

  const N = 60;
  const closes_60 = closesAll.slice(-N);
  const lastClose = closesAll[closesAll.length - 1];
  const firstClose = closesAll[0];

  return {
    json: {
      symbol,
      last_close: lastClose,
      first_close: firstClose,
      closes_60,
      meta: {
        nb_candles: nbBars ?? bars.length,
        interval: j.interval ?? null,
        period: j.period ?? null,
        source: j.source ?? null,
        generated_at: new Date().toISOString(),
      }
    }
  };
});

// Normalize Tech Metrics (fix: handle {status,count,items} from /tech/watch/latest)
