// n8n Code node: "MLOps Executive Pack"
// Produit :
// - mlops_kpis (KPI exécutifs)
// - mlops_decision (drift + retrain decision)
// - mlops_visual_md (Champion vs Challenger visuel + KPIs)

// ---------- helpers ----------
const isObj = (v) => v && typeof v === "object" && !Array.isArray(v);

function deepMerge(target, src) {
  if (!isObj(src)) return target;
  for (const [k, v] of Object.entries(src)) {
    if (v === undefined || v === null) continue;

    if (Array.isArray(v)) {
      const cur = target[k];
      if (!Array.isArray(cur) || v.length >= cur.length) target[k] = v;
      continue;
    }
    if (isObj(v)) {
      if (!isObj(target[k])) target[k] = {};
      deepMerge(target[k], v);
      continue;
    }
    target[k] = v;
  }
  return target;
}

const n = (x, d = null) => {
  const v = Number(x);
  return Number.isFinite(v) ? v : d;
};

const fmt = (x, digits = 3) => {
  const v = n(x, null);
  return v === null ? "-" : v.toFixed(digits);
};

const nowIso = () => new Date().toISOString();

function tryGetFromNode(name) {
  // Compat n8n : certains environnements supportent $('Node').first()
  try { return $(name).first().json; } catch (e) {}
  return null;
}

// ---------- collect inputs ----------
let merged = {};
for (const it of items) if (it?.json) deepMerge(merged, it.json);

// On tente aussi d’aller chercher directement depuis les nodes, si possible.
const trainRaw = tryGetFromNode("QuickTrain /mlops/train/market") || merged;
const metricsRaw = tryGetFromNode("Metrics /mlops/metrics/daily") || merged;
const champsRaw = tryGetFromNode("Get /mlops/champions") || merged;

// Shapes attendues :
const train = trainRaw?.results ? trainRaw : (trainRaw?.data?.results ? trainRaw.data : trainRaw);
const champions = champsRaw && !champsRaw.results ? champsRaw : (champsRaw?.data ? champsRaw.data : champsRaw);
const daily = metricsRaw?.metrics ? metricsRaw : (metricsRaw?.data?.metrics ? metricsRaw.data : metricsRaw);

// ---------- build challenger rows from training output ----------
const challengerRows = [];
const trainResults = train?.results && typeof train.results === "object" ? train.results : {};
for (const [symbol, m] of Object.entries(trainResults)) {
  // On estime un "score challenger" avec le même principe que registry : silhouette - ae_reconstruction
  // (registry: score = silhouette + ae_reconstruction * -1) :contentReference[oaicite:4]{index=4}
  const sil = n(m?.silhouette, null);
  const ae = n(m?.ae_reconstruction, null);
  const score = (sil !== null && ae !== null) ? (sil - ae) : null;

  challengerRows.push({
    symbol,
    challenger_run_id: train?.run_id || train?.runId || "",
    challenger_score: score,
    challenger_silhouette: sil,
    challenger_ae: ae,
  });
}

// ---------- build champion rows from registry ----------
const champEntries = Object.entries(champions || {}).filter(([, v]) => isObj(v));
const championRows = champEntries.map(([symbol, payload]) => {
  const mm = payload.metrics || {};
  return {
    symbol,
    champion_run_id: payload.run_id || "",
    champion_score: n(payload.score, null),
    champion_silhouette: n(mm.silhouette, null),
    champion_ae: n(mm.ae_reconstruction, null),
  };
});

// Index champions by symbol
const champBySym = Object.fromEntries(championRows.map(r => [r.symbol, r]));

// ---------- Champion vs Challenger verdict ----------
const compareRows = [];
let replacedCount = 0;

for (const ch of challengerRows) {
  const sym = ch.symbol;
  const cp = champBySym[sym] || null;

  const cRun = String(ch.challenger_run_id || "");
  const pRun = String(cp?.champion_run_id || "");

  // Heuristique simple : si run_id différent → probablement pas le même modèle en registry
  // (dans ton backend, train met à jour la registry après l’expérience) :contentReference[oaicite:5]{index=5}
  const changed = (cRun && pRun && cRun !== pRun);
  if (changed) replacedCount++;

  const delta = (cp && ch.challenger_score !== null && cp.champion_score !== null)
    ? (ch.challenger_score - cp.champion_score)
    : null;

  // Verdict “visuel”
  let verdict = "⚪ Inconnu";
  if (delta !== null) {
    verdict = delta > 0.01 ? "🟢 Challenger ↑" : (delta < -0.01 ? "🔴 Challenger ↓" : "⚪ Stable");
  } else if (changed) {
    verdict = "🟠 Changement run_id";
  }

  compareRows.push({
    symbol: sym,
    verdict,
    champion_score: cp?.champion_score ?? null,
    challenger_score: ch.challenger_score ?? null,
    delta_score: delta,
    champion_run_id: pRun || "-",
    challenger_run_id: cRun || "-",
    silhouette: ch.challenger_silhouette ?? cp?.champion_silhouette ?? null,
    ae: ch.challenger_ae ?? cp?.champion_ae ?? null,
  });
}

// Tri par delta ou challenger score
compareRows.sort((a, b) => {
  const da = n(a.delta_score, -999);
  const db = n(b.delta_score, -999);
  if (db !== da) return db - da;
  return n(b.challenger_score, -999) - n(a.challenger_score, -999);
});

// ---------- Drift & Retrain decision ----------
const dailyMetrics = Array.isArray(daily?.metrics) ? daily.metrics : [];
const driftVals = dailyMetrics.map(r => n(r.drift_score, null)).filter(v => v !== null);

const driftAvg = driftVals.length ? driftVals.reduce((s, x) => s + x, 0) / driftVals.length : null;
const driftMax = driftVals.length ? Math.max(...driftVals) : null;

const TH_AVG = 0.25;   // seuil drift moyen (ajuste si tu veux)
const TH_MAX = 0.50;   // seuil drift max
const TH_BAD = 0.40;   // drift “fort” par symbole

const nbBad = dailyMetrics.filter(r => n(r.drift_score, 0) >= TH_BAD).length;
const retrainRecommended = (driftAvg !== null && driftAvg >= TH_AVG) || (driftMax !== null && driftMax >= TH_MAX);

const decision = {
  type: "retrain_decision",
  retrain_recommended: !!retrainRecommended,
  drift_avg: driftAvg,
  drift_max: driftMax,
  nb_symbols: dailyMetrics.length,
  nb_drift_high: nbBad,
  rules: {
    drift_avg_threshold: TH_AVG,
    drift_max_threshold: TH_MAX,
    drift_high_per_symbol: TH_BAD,
  },
  explanation: retrainRecommended
    ? `Retrain recommandé : drift moyen (${fmt(driftAvg,3)}) ou drift max (${fmt(driftMax,3)}) au-dessus des seuils.`
    : `Retrain non nécessaire : drift moyen (${fmt(driftAvg,3)}) et drift max (${fmt(driftMax,3)}) sous contrôle.`,
  generated_at: nowIso(),
};

// ---------- KPI exécutifs ----------
const expected = challengerRows.length || 0;
const okSymbols = dailyMetrics.length;

const kpis = {
  type: "mlops_kpis",
  pipeline_status: (expected && okSymbols < expected) ? "⚠ PARTIEL" : "✅ OK",
  nb_symbols_requested: expected,
  nb_symbols_ok: okSymbols,
  nb_champions: championRows.length,
  champions_changed_runid: replacedCount,
  drift_avg: driftAvg,
  drift_max: driftMax,
  retrain_recommended: !!retrainRecommended,
  generated_at: nowIso(),
};

// ---------- Visual markdown (pour email / logs / PDF si besoin) ----------
let md = "";
md += `## 🧠 MLOps Daily – Executive\n\n`;
md += `**Pipeline**: ${kpis.pipeline_status}  ·  **Symbols**: ${kpis.nb_symbols_ok}/${kpis.nb_symbols_requested}  ·  **Retrain**: ${kpis.retrain_recommended ? "🟠 OUI" : "🟢 NON"}\n\n`;
md += `### KPI\n`;
md += `- Drift moyen: **${fmt(kpis.drift_avg, 3)}** (seuil ${TH_AVG})\n`;
md += `- Drift max: **${fmt(kpis.drift_max, 3)}** (seuil ${TH_MAX})\n`;
md += `- Champions: **${kpis.nb_champions}**  ·  run_id changés: **${kpis.champions_changed_runid}**\n\n`;

md += `### Champion vs Challenger (visuel)\n\n`;
md += `| Symbole | Verdict | Δ score | Champion score | Challenger score | Silhouette | AE |\n`;
md += `|---|---|---:|---:|---:|---:|---:|\n`;

for (const r of compareRows.slice(0, 12)) {
  md += `| ${r.symbol} | ${r.verdict} | ${fmt(r.delta_score, 3)} | ${fmt(r.champion_score, 3)} | ${fmt(r.challenger_score, 3)} | ${fmt(r.silhouette, 3)} | ${fmt(r.ae, 3)} |\n`;
}

md += `\n> ${decision.explanation}\n`;

return [{
  json: {
    ...merged,
    mlops_kpis: kpis,
    mlops_decision: decision,
    mlops_compare_rows: compareRows,
    mlops_visual_md: md,
  }
}];

